<span class="line"><span style="color:#9399B2;">    )</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">MessageStream</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> ProviderError</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
